module RefModule(
	input wire clk,
	input wire clear,
	input wire en,
	input wire [15:0] D,
	output reg [15:0] Q
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (clear)
		Q <= 16'b0000000000000000;
	else if (en)
		Q <= D;
end
endmodule
